mapper.select:
/* com.shop.mapper.product.ProductMng.selectProdInfoList */ SELECT TP.ID AS id , TP.PARTNER_ID AS partnerId , PT.PARTNER_NM AS partnerNm , PT.SIZE_INFO AS sizeInfo , TP.PROD_CD AS prodCd , TP.PROD_NM AS prodNm , TP.COMPOSITION AS composition , TP.SINSANG_NO AS sinsangNo , TP.REP_FILE_ID AS repFileId , TP.DETAIL_FILE_ID AS detailFileId , TP.SIZE_FILE_ID AS sizeFileId , TP.ETC_FILE_ID AS etcFileId , TP.MAKE_YMD AS makeYmd , TP.ORG_AMT AS orgAmt , TP.SELL_AMT AS sellAmt , TP.DISCOUNT_RATE AS discountRate , TPD.prodColors , TPD.prodSizes , COALESCE(TPD.prodDetCnt, 0) AS prodDetCnt , COALESCE(FD_REP.FILE_CNT, 0) AS repFileIdCnt , COALESCE(FD_DETAIL.FILE_CNT, 0) AS detailFileIdCnt , COALESCE(FD_SIZE.FILE_CNT, 0) AS sizeFileIdCnt , COALESCE(FD_ETC.FILE_CNT, 0) AS etcFileIdCnt , TP.IS_SPRING , TP.IS_SUMMER , TP.IS_AUTUMN , TP.IS_WINTER , CONCAT( CASE WHEN TP.IS_SPRING = 'Y' THEN 'S' ELSE '_' END, CASE WHEN TP.IS_SUMMER = 'Y' THEN 'S' ELSE '_' END, CASE WHEN TP.IS_AUTUMN = 'Y' THEN 'F' ELSE '_' END, CASE WHEN TP.IS_WINTER = 'Y' THEN 'W' ELSE '_' END ) AS SEASON , COALESCE(CP.REL_CNT, 0) AS relCount , TP.DOMAE_ID AS domaeId , DOMAE.CODE_NM AS domaeNm , TP.SHOW_YN AS showYn , TP.DET_INFO AS detInfo FROM TB_PRODUCT TP INNER JOIN ( SELECT PRODUCT_ID , STRING_AGG(PRODUCT_DET_COLOR, ',') AS prodColors , STRING_AGG(DISTINCT PRODUCT_DET_SIZE, ',') AS prodSizes , COUNT(1) AS prodDetCnt FROM TB_PRODUCT_DET WHERE DEL_YN = 'N' GROUP BY PRODUCT_ID ) TPD ON TPD.PRODUCT_ID = TP.ID INNER JOIN TB_PARTNER_CODE DOMAE ON DOMAE.ID = TP.DOMAE_ID AND DOMAE.PARTNER_ID = TP.PARTNER_ID AND DOMAE.CODE_UPPER = 'P0006' LEFT JOIN TB_PARTNER PT ON PT.ID = TP.PARTNER_ID LEFT JOIN ( SELECT FILE_ID, COUNT(1) AS FILE_CNT FROM TB_FILE_DET WHERE DEL_YN = 'N' GROUP BY FILE_ID ) FD_REP ON FD_REP.FILE_ID = TP.REP_FILE_ID LEFT JOIN ( SELECT FILE_ID, COUNT(1) AS FILE_CNT FROM TB_FILE_DET WHERE DEL_YN = 'N' GROUP BY FILE_ID ) FD_DETAIL ON FD_DETAIL.FILE_ID = TP.DETAIL_FILE_ID LEFT JOIN ( SELECT FILE_ID, COUNT(1) AS FILE_CNT FROM TB_FILE_DET WHERE DEL_YN = 'N' GROUP BY FILE_ID ) FD_SIZE ON FD_SIZE.FILE_ID = TP.SIZE_FILE_ID LEFT JOIN ( SELECT FILE_ID, COUNT(1) AS FILE_CNT FROM TB_FILE_DET WHERE DEL_YN = 'N' GROUP BY FILE_ID ) FD_ETC ON FD_ETC.FILE_ID = TP.ETC_FILE_ID LEFT JOIN ( SELECT PRODUCT_ID, COUNT(1) AS REL_CNT FROM TB_CONTENTS_PRODUCT WHERE DEL_YN = 'N' GROUP BY PRODUCT_ID ) CP ON CP.PRODUCT_ID = TP.ID
AND TP.DEL_YN = 'N'
AND TP.PROD_NM LIKE CONCAT('%', #{prodNm}, '%')
AND TP.PARTNER_ID = #{partnerId}
AND TP.DOMAE_ID = #{domaeId}
AND TP.SHOW_YN = #{showYn}
AND (
OR TP.IS_SPRING = 'Y'
OR TP.IS_SUMMER = 'Y'
OR TP.IS_AUTUMN = 'Y'
OR TP.IS_WINTER = 'Y'
)
ORDER BY TP.ID DESC

/* com.shop.mapper.product.ProductMng.selectProdDetInfo */ SELECT TPD.ID AS id , TPD.PRODUCT_ID AS productId , TPD.PRODUCT_DET_SEQ AS productDetSeq , TPD.PRODUCT_DET_SIZE AS productDetSize , TPD.PRODUCT_DET_COLOR AS productDetColor , TPD.STNDR_COLOR AS stndrColor , TPD.SKU_DISCOUNT_RATE AS skuDiscountRate , TPD.FILE_ID AS fileId , TPD.SLEEP_YN AS sleepYn , TPD.PRODUCT_DET_CNTN AS productDetCntn FROM TB_PRODUCT_DET TPD
AND TPD.DEL_YN = 'N'
AND TPD.PRODUCT_ID = #{prodId}
AND TPD.PRODUCT_DET_COLOR = #{prodDetColor}
ORDER BY TPD.ID

/* com.shop.mapper.product.ProductMng.selectCategoryProductInfoList */ SELECT TP.ID AS id , TP.PARTNER_ID AS partnerId , TP.PROD_CD AS prodCd , TP.PROD_NM AS prodNm , TP.COMPOSITION AS composition , TP.SINSANG_NO AS sinsangNo , TP.REP_FILE_ID AS repFileId , TP.DETAIL_FILE_ID AS detailFileId , TP.SIZE_FILE_ID AS sizeFileId , TP.ETC_FILE_ID AS etcFileId , TP.MAKE_YMD AS makeYmd , TP.ORG_AMT AS orgAmt , TP.SELL_AMT AS sellAmt , TP.DISCOUNT_RATE AS discountRate , TP.IS_SPRING , TP.IS_SUMMER , TP.IS_AUTUMN , TP.IS_WINTER , STRING_AGG(TPD.PRODUCT_DET_COLOR, ',') AS prodColors , STRING_AGG(DISTINCT TPD.PRODUCT_DET_SIZE, ',') AS prodSizes , CPD.ID AS categoryProductId , FN_GET_PARTNER_CODE_ID('P0001', CPD.CATEGORY_ID) AS categoryNm , CPD.SEQ AS seq , CPD.CATEGORY_ID AS categoryId FROM TB_PRODUCT TP JOIN TB_CATEGORY_PRODUCT CPD ON TP.ID = CPD.PRODUCT_ID AND CPD.DEL_YN = 'N' LEFT JOIN TB_PRODUCT_DET TPD ON TP.ID = TPD.PRODUCT_ID AND TPD.DEL_YN = 'N'
AND TP.DEL_YN = 'N'
AND CPD.CATEGORY_ID = #{categoryId}
GROUP BY TP.ID, CPD.ID, CPD.SEQ ORDER BY CPD.SEQ;

mapper.insert:
/* com.shop.mapper.product.ProductMng.insertProduct */
INSERT INTO TB_PRODUCT (
      PARTNER_ID
    , PROD_CD
    , PROD_NM
    , COMPOSITION
    , SINSANG_NO

    , REP_FILE_ID


    , DETAIL_FILE_ID


    , SIZE_FILE_ID


    , ETC_FILE_ID

    , MAKE_YMD

    , ORG_AMT


    , SELL_AMT


    , DISCOUNT_RATE

    , CRE_USER
    , UPD_USER

    , IS_SPRING


    , IS_SUMMER


    , IS_AUTUMN


    , IS_WINTER


    , DOMAE_ID


    , THICK_TP


    , SPAN_TP


    , SHOW_TP


    , LAUNDRY_TP


    , TRANS_TP


    , DET_INFO

) VALUES (
      #{partnerId}
    , FN_GET_NEXT_PRODUCT_CODE(#{partnerId})
    , #{prodNm}
    , #{composition}
    , #{sinsangNo}

    , #{repFileId}


    , #{detailFileId}


    , #{sizeFileId}


    , #{etcFileId}

    , #{makeYmd}

    , #{orgAmt}


    , #{sellAmt}


    , #{discountRate}

    , #{creUser}
    , #{updUser}

    , #{isSpring}


    , #{isSummer}


    , #{isAutumn}


    , #{isWinter}


    , #{domaeId}


    , #{thickTp}


    , #{spanTp}


    , #{showTp}


    , #{laundryTp}


    , #{transTp}


    , #{detInfo}

)

/* com.shop.mapper.product.ProductMng.insertProductDet */
INSERT INTO TB_PRODUCT_DET (
      PRODUCT_ID
    , PRODUCT_DET_SEQ
    , PRODUCT_DET_SIZE
    , PRODUCT_DET_COLOR
    , SKU_DISCOUNT_RATE

    , FILE_ID


    , PRODUCT_DET_CNTN


    , STNDR_COLOR

    , SLEEP_YN
    , CRE_USER
    , UPD_USER
) VALUES (
      #{productId}
    , GET_NEXT_PRODUCT_DET_SEQ(#{productId})
    , #{productDetSize}
    , #{productDetColor}
    , #{skuDiscountRate}

    , #{fileId}


    , #{productDetCntn}


    , #{stndrColor}

    , #{sleepYn}
    , #{creUser}
    , #{updUser}
)

mapper.update:
/* com.shop.mapper.product.ProductMng.updateProduct */
UPDATE TB_PRODUCT SET
      UPD_TM   = NOW()
    , UPD_USER = #{updUser}

    , PROD_NM = #{prodNm}


    , COMPOSITION = #{composition}


    , SINSANG_NO = #{sinsangNo}


    , MAKE_YMD = #{makeYmd}


    , ORG_AMT = #{orgAmt}


    , SELL_AMT = #{sellAmt}


    , DISCOUNT_RATE = #{discountRate}

    , IS_SPRING = #{isSpring}
    , IS_SUMMER = #{isSummer}
    , IS_AUTUMN = #{isAutumn}
    , IS_WINTER = #{isWinter}

    , DOMAE_ID = #{domaeId}

    , THICK_TP    = #{thickTp}
    , SPAN_TP     = #{spanTp}
    , SHOW_YN     = #{showYn}
    , LAUNDRY_TP  = #{laundryTp}
    , TRANS_TP     = #{transTp}
    , DET_INFO  = #{detInfo}
WHERE ID = #{id}

/* com.shop.mapper.product.ProductMng.updateProductDet */
UPDATE TB_PRODUCT_DET SET
      UPD_TM   = NOW()
    , UPD_USER = #{updUser}

    , PRODUCT_ID = #{productId}


    , PRODUCT_DET_SEQ = #{productDetSeq}


    , PRODUCT_DET_SIZE = #{productDetSize}


    , PRODUCT_DET_COLOR = #{productDetColor}


    , STNDR_COLOR = #{stndrColor}


    , SKU_DISCOUNT_RATE = #{skuDiscountRate}


    , FILE_ID = #{fileId}


    , SLEEP_YN = #{sleepYn}


    , PRODUCT_DET_CNTN = #{productDetCntn}

WHERE ID = #{id}

/* com.shop.mapper.product.ProductMng.deleteProduct */
UPDATE TB_PRODUCT SET
      UPD_TM   = NOW()
    , UPD_USER = #{updUser}
    , DEL_YN = 'Y'
WHERE ID = #{id}

/* com.shop.mapper.product.ProductMng.deleteProductDet */
UPDATE TB_PRODUCT_DET SET
      UPD_TM   = NOW()
    , UPD_USER = #{updUser}
    , DEL_YN = 'Y'
WHERE ID = #{id}

mapper.select:
/* com.shop.mapper.product.ProductMng.selectProdInfoListWithExclusion */ SELECT TP.ID AS id , TP.PARTNER_ID AS partnerId , TP.PROD_CD AS prodCd , TP.PROD_NM AS prodNm , STRING_AGG(TPD.PRODUCT_DET_COLOR, ',') AS prodColors , STRING_AGG(DISTINCT TPD.PRODUCT_DET_SIZE, ',') AS prodSizes FROM TB_PRODUCT TP LEFT JOIN TB_PRODUCT_DET TPD ON TP.ID = TPD.PRODUCT_ID AND TPD.DEL_YN = 'N'
AND TP.DEL_YN = 'N'
AND TP.PROD_NM LIKE CONCAT('%' ,#{prodNm} ,'%')
AND NOT EXISTS ( SELECT 1 FROM TB_CATEGORY_PRODUCT CPD
AND CPD.DEL_YN = 'N' AND CPD.PRODUCT_ID = TP.ID
AND CPD.CATEGORY_ID = #{categoryId}
)
GROUP BY TP.ID ORDER BY TP.ID;

mapper.update:
/* com.shop.mapper.product.ProductMng.updateCategoryProduct */ UPDATE TB_CATEGORY_PRODUCT SET
SEQ = #{seq},
CATEGORY_ID = #{categoryId},
PRODUCT_ID = #{productId},
UPD_USER = #{updUser}, UPD_TM = NOW() WHERE ID = #{id}

/* com.shop.mapper.product.ProductMng.deleteCategoryProduct */
UPDATE TB_CATEGORY_PRODUCT SET
      UPD_TM = NOW()
    , UPD_USER = #{updUser}
    , DEL_YN = 'Y'
WHERE ID = #{id}

/* com.shop.mapper.product.ProductMng.deleteCategoryProductByProductId */
UPDATE TB_CATEGORY_PRODUCT SET
      UPD_TM = NOW()
    , UPD_USER = #{updUser}
    , DEL_YN = 'Y'
WHERE PRODUCT_ID = #{id}
  AND DEL_YN = 'N'
